// Script: generar_09_prevencion_modo_claro.js
// Que hace: actualiza DOS archivos a la nueva paleta clara cafe/crema/dorado:
//   1) components/PesoTracker.tsx -- el grafico de tendencia de peso que
//      se muestra en la pestana Peso de Prevencion.
//   2) app/prevencion/page.tsx -- las 7 pestanas completas (Peso, Vacunas,
//      Antiparasitarios, Medicamentos, Enfermedades, Observaciones, Examenes),
//      manteniendo TODA la logica intacta incluyendo la subida de PDFs.
//
// Cambios de color (fondo oscuro -> paleta clara):
//   #0F1117 -> #F5EDE3 (fondo principal crema)
//   #232840 -> #FFFCF8 (tarjetas blanco calido)
//   #1E2333 -> #FBEAD9 (fondos secundarios durazno claro)
//   #8A8FA8 -> #8A7560 (texto secundario cafe)
//   #F0EEE8 -> #3D2B1F (texto principal cafe oscuro)
//   #E8A84C -> #FFBD59 (dorado de marca actualizado)
//   bordes/fondos blancos translucidos -> #EEE2D4 (cafe claro)
//
// Los colores de cada item (verde=vacunas, amarillo=antiparasitarios,
// azul=medicamentos reservado, morado=examenes) y los colores de semaforo
// de salud NO cambian.
//
// Como correrlo: node generar_09_prevencion_modo_claro.js
// Confirma que diga "OK: components/PesoTracker.tsx" y "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('components/PesoTracker.tsx', "");
escribir('app/prevencion/page.tsx', "");
